struct ExpressionTree {
    children: HashMap<String, Arc<ExpressionTree>>,
    operator: Option<String>,
}

impl ExpressionTree {
    fn new() -> Self {
        ExpressionTree {
            children: HashMap::new(),
            operator: None,
        }
    }

    fn add_child(&mut self, key: String, child: Arc<ExpressionTree>) {
        self.children.insert(key, child);
    }
}

fn build_parser() -> Arc<ExpressionTree> {
    let mut root = ExpressionTree::new();

    let child1: Arc<ExpressionTree> = Arc::new(ExpressionTree::new());
    let mut mutable_child1 = ExpressionTree::new();
    mutable_child1.add_child("a".to_string(), Arc::new(ExpressionTree::new()));

    let child2: Arc<ExpressionTree> = Arc::new(ExpressionTree::new());
    let mut mutable_child2 = ExpressionTree::new();
    mutable_child2.add_child("b".to_string(), Arc::new(ExpressionTree::new()));

    { 
        let mut temp_root: ExpressionTree = ExpressionTree::new();
        temp_root.add_child("left".to_string(), Arc::clone(&child1));
        temp_root.add_child("right".to_string(), Arc::clone(&child2));

        let shared_node = Arc::new(temp_root);

        let mut final_root: ExpressionTree = ExpressionTree::new();
        final_root.add_child("result".to_string(), Arc::clone(&shared_node));
    }

    Arc::new(ExpressionTree::new())
