use std::sync::Arc;
use std::thread;
use std::time::Duration;

struct LargeData {
    content: String,
}

impl Clone for LargeData {
    fn clone(&self) -> Self {
        LargeData { content: self.content.clone() }
    }
}

fn main() {
    let initial_data = Arc::new(LargeData { content: String::from("Initial state") });

    let reader_handle: thread::JoinHandle<Result<(), ()>> = thread::spawn(move || {
        for i in 0..3 {
            thread::sleep(Duration::from_millis(100));
            println!("Reader thread: successfully read data version.");
        }
        Ok(())
    });

    let mut shared_data = initial_data.clone();

    for i in 0..2 {
        thread::sleep(Duration::from_millis(50));
        println!("nWriter thread: preparing update version {}", i + 1);
        let new_content = format!("Updated content for cycle {}", i + 1);
        let updated_data = Arc::new(LargeData { content: new_content.clone() });

        // Simulate the copy-on-write mechanism conceptually by replacing the Arc pointer
        shared_data = updated_data;
        println!("Writer thread: wrote new data version to shared memory location.");
    }

    thread::sleep(Duration::from_millis(100));

    match reader_handle.join().unwrap() {
        Ok(_) => println!("nProgram finished successfully."),
        Err(_) => eprintln!("nError detected during execution!"),
    }
}

use std::collections::HashMap;
use std::sync::Mutex;
use std::sync::Arc;
use std::thread;

struct CacheEntry {
    data: String,
}

impl Clone for CacheEntry {
    fn clone(&self) -> Self {
        CacheEntry { data: self.data.clone() }
    }
}

fn main() {
    let mut initial_map: HashMap<String, CacheEntry> = HashMap::new();
    initial_map.insert("google.com".to_string(), CacheEntry { data: "142.250.1สุข.100".to_string() });

    let cache_arc = Arc::new(Mutex::new(initial_map));

    let reader_cache = Arc::clone(&cache_arc);
    let writer_cache = Arc::clone(&cache_arc);

    let handle1 = thread::spawn(move || {
        println!("Reader 1: Attempting to read cache...");
        match reader_cache.lock() {
            Ok(guard) => {
                if let Some(entry) = guard.get("google.com") {
                    println!("Reader 1 Success: Found data for google.com -> {}", entry.data);
                }
            },
            Err(e) => println!("Reader 1 Error: Failed to lock cache: {}", e),
        }
    });

    let handle2 = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(50));
        println!("Writer 2: Attempting to update cache...");
        {
            let mut guard = writer_cache.lock().unwrap();
            if let Some(entry) = guard.get_mut("example.org") {
                *entry = CacheEntry { data: "93.8.32.1".to_string() };
            } else {
                 guard.insert("example.org".to_string(), CacheEntry { data: "93.8.32.1".to_string() });
            }
        }
        println!("Writer 2 Success: Cache updated.");
    });

    handle1.join().unwrap();
    handle2.join().unwrap();

    let final_guard = cache_arc.lock().unwrap();
    if let Some(entry) = final_guard.get("example.org") {
        println!("Main: Final check for example.org -> {}", entry.data);
    }
}

use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

struct SharedData {
    value: AtomicUsize,
}

impl Clone for SharedData {
    fn clone(&self) -> Self {
        SharedData { value: AtomicUsize::new(0) }
    }
}

fn main() {
    let initial_data = Arc::new(SharedData {
        value: AtomicUsize::new(10)
    });

    let reader_clone = Arc::clone(&initial_data);
    let writer_clone = Arc::clone(&initial_data);

    let reader_handle = std::thread::spawn(move || {
        println!("Reader thread sees initial value: {}", reader_clone.value.load(Ordering::Relaxed));
        std::thread::sleep(std::time::Duration::from_millis(50));
    });

    let writer_handle = std::thread::spawn(move || {
        writer_clone.value.fetch_add(1, Ordering::SeqCst);
        println!("Writer thread updated value to: {}", writer_clone.value.load(Ordering::Relaxed));
        std::thread::sleep(std::time::Duration::from_millis(50));
    });

    reader_handle.join().unwrap();
    writer_handle.join().unwrap();

    println!("Final shared value: {}", initial_data.value.load(Ordering::Relaxed));
}

use std::collections::HashMap;
use std::sync::Arc;

struct DataView {
    data: HashMap<String, Vec<String>>,
}

impl Clone for DataView {
    fn clone(&self) -> Self {
        DataView { data: self.data.clone() }
    }
}

struct CoWArc<T> {
    inner: Arc<std::sync::Mutex<T>>,
}

impl<T> CoWArc<T> {
    fn new(initial_data: T) -> Self {
        CoWArc { inner: Arc::new(std::sync::Mutex::new(initial_data)) }
    }

    fn read_only(&self) -> std::sync::MutexGuard<T> {
        self.inner.lock().unwrap()
    }

    fn write(&self, modifier: impl FnOnce(&mut T)) {
        let mut data = self.read_only();
        modifier(&mut *data)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let initial_dataset = HashMap::from([ 
        ("id".to_string(), vec!["1".to_string(), "2".to_string()]), 
        ("value".to_string(), vec!["10.5".to_string(), "20.1".to_string()]), 
        ("source".to_string(), vec!["A".to_string(), "B".to_string()]), 
    ]);

    let shared_data = CoWArc::new(DataView { data: initial_dataset });

    println!("Original dataset established.");

    { 
        let _guard = shared_data.read_only();
        println!("Reader 1 sees {} columns.", shared_data.read_only().data.len());
    }

    shared_data.write(|view| {
        if let Some(source) = view.data.get_mut("source") {
            source.push("C".to_string());
        }
    });

    { 
        let _guard = shared_data.read_only();
        println!("Reader 2 sees updated data state.");
    }

    Ok(())
}
